import App from "./components/App/App";
import "./index.css";

import { updateAllRelativeTimestamps } from "./utils/dates";

import { React, ReactDOM } from "./cdn";
const root = ReactDOM.createRoot(document.getElementById("root") as HTMLElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

window.onload = (_event: Event) => {
  // dates when we have the page opened for a long time
  setInterval(updateAllRelativeTimestamps, 60000);
};
