import { dateToStr, dateToHours } from "../../utils/dates";
import { IconR, IconZ } from "../Simple/Image";
import "./Summary.css";

import { useState, useEffect } from "../../cdn";
import type { Item, Search } from "../../types";
import { CheckBox } from "./CheckBox";

export const Summary = ({
  data,
  setItemsSelectable,
  setActivePage1,
}: {
  data: any;
  setItemsSelectable: (items: Item[]) => void;
  setActivePage1: (page: number) => void;
}) => {
  const [isStcHidden, setIsStcHidden] = useState(false);
  const [isFlatHidden, setIsFlatHidden] = useState(false);
  const [isDistanceApplied, setIsDistanceApplied] = useState(false);
  const [distValue, setDistValue] = useState("0.3");
  const [isAddrFilterApplied, setIsAddrFilterApplied] = useState(false);
  const [addrFilterValue, setAddrFilterValue] = useState("");

  // Set Selectable items
  useEffect(() => {
    const maxDistance = parseFloat(distValue);
    const addressSearch = addrFilterValue.toUpperCase().replaceAll(" ", "");
    const itemsSelectable: Item[] = [];
    data.items.forEach((item: Item) => {
      const addressFull = ((item.address_street_num || "") + item.address + item.address_postcode)
        .toUpperCase()
        .replaceAll(" ", "");
      if (
        (isStcHidden && item.sold_let) ||
        (isFlatHidden && item.property_group_icon === "🏢") ||
        (isDistanceApplied && item.closest && maxDistance && item.closest.miles > maxDistance) ||
        (isAddrFilterApplied && !addressFull.includes(addressSearch))
      ) {
        /* item should be hidden */
      } else {
        itemsSelectable.push(item);
      }
    });
    setItemsSelectable(itemsSelectable);
    console.log("itemsSelectable", itemsSelectable.length);

    // Go to 1st page as indexes changed
    setActivePage1(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStcHidden, isFlatHidden, isDistanceApplied, isAddrFilterApplied]);

  const numSTCs = data.items.filter((item: Item) => item.sold_let).length;
  const numFlats = data.items.filter((item: Item) => item.property_group_icon === "🏢").length;

  return (
    <>
      <h1 style={{ textTransform: "uppercase" }}>{data.region}</h1>
      <h5>{data.title}</h5>
      <UpdatedOn data={data} />
      <AllSearches searches={data.searches} />

      <CheckBox
        checkState={[isStcHidden, setIsStcHidden]}
        labelBefore={`Exclude the ${numSTCs} STCs`}
      />
      <CheckBox
        checkState={[isFlatHidden, setIsFlatHidden]}
        labelBefore={`Exclude the ${numFlats} flats`}
      />
      <CheckBox
        checkState={[isDistanceApplied, setIsDistanceApplied]}
        labelBefore="Exclude further than"
        maxWidth="3rem"
        labelAfter="miles"
        textState={[distValue, setDistValue]}
      />
      <CheckBox
        checkState={[isAddrFilterApplied, setIsAddrFilterApplied]}
        labelBefore="Address:"
        maxWidth="10rem"
        textState={[addrFilterValue, setAddrFilterValue]}
      />
    </>
  );
};

const UpdatedOn = ({ data }: any) => {
  return (
    <p>
      Updated{" "}
      <span
        id="x-updated-relative"
        className="x-date-relative"
        data-convert="hours"
        data-date={data.updated_on}
      >
        {dateToHours(data.updated_on)}
      </span>{" "}
      ago
      <br />
      (on <span>{dateToStr(data.updated_on)}</span>
      )
      <br />
      next check starts in:{" "}
      <span
        id="x-nexton-relative"
        className="x-date-relative"
        data-convert="hours-negative"
        data-date={data.next_on}
      >
        {dateToHours(data.next_on, true)}
      </span>
    </p>
  );
};

const AllSearches = ({ searches }: { searches: Search[] }) => {
  return (
    <p>
      Results based on <IconR style={{ verticalAlign: "baseline" }} /> searches:
      <br />
      {searches &&
        searches
          .map((search: Search, index: number) => <SearchItem key={index} search={search} />)
          .reduce((prev: any, curr: any) => [prev, " ◆ ", curr] as any)}
    </p>
  );
};

const SearchItem = ({ search }: { search: Search }) => {
  return (
    <span className="x-nowrap">
      <strong>{search.name}</strong>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_r}>
        <IconR isLink={true} style={{ verticalAlign: "sub" }} />
      </a>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_z}>
        <IconZ isLink={true} style={{ verticalAlign: "sub" }} />
      </a>
    </span>
  );
};

export default Summary;
