import { Form } from "../../cdn";
import type { ChangeEvent } from "../../cdn";
import "./CheckBox.css";

export const CheckBox = ({
  checkState,
  labelBefore,
  labelAfter,
  maxWidth = "3rem",
  textState,
}: {
  checkState: [boolean, (newValue: boolean) => void];
  labelBefore: string;
  labelAfter?: string;
  maxWidth?: string;
  textState?: [string, (newValue: string) => void];
}) => {
  const [isApplied, setIsApplied] = checkState;

  return (
    <Form>
      <Form.Check
        type="switch"
        onChange={(e: ChangeEvent) => setIsApplied((e.target as HTMLInputElement).checked)}
        checked={isApplied}
      />
      <p>{labelBefore}</p>
      {textState && (
        <TextComponent
          textState={textState}
          setIsApplied={setIsApplied}
          maxWidth={maxWidth}
          labelAfter={labelAfter}
        />
      )}
    </Form>
  );
};

const TextComponent = ({
  textState,
  setIsApplied,
  maxWidth,
  labelAfter,
}: {
  textState: [string, (newValue: string) => void];
  setIsApplied: (newValue: boolean) => void;
  maxWidth: string;
  labelAfter?: string;
}) => {
  const [textValue, setTextValue] = textState;
  const onChangeText = (e: ChangeEvent) => {
    setTextValue((e.target as HTMLInputElement).value);
    setIsApplied(false);
  };
  const onKeyDown = (event: KeyboardEvent) => {
    if (event.key === "Enter") {
      setIsApplied(true);
      event.preventDefault();
    } else {
      setIsApplied(false);
    }
  };
  return (
    <>
      <Form.Control
        value={textValue}
        onChange={onChangeText}
        style={{ maxWidth: maxWidth }}
        onKeyDown={onKeyDown}
      />
      {labelAfter && <p>{labelAfter}</p>}
    </>
  );
};
